Here's the result of running `cat -n` on a snippet of src/pages/CheckinPage.tsx
     1→import React, { useState, useEffect, useCallback, useMemo } from 'react';
     2→import {
     3→  CheckCircle, CheckCircle2, XCircle, RefreshCw, Phone, Banknote,
     4→  Edit3, Trash2, Search, MapPin, Star, Eye, EyeOff, X, Copy, Check,
     5→  ChevronLeft, ChevronRight, ExternalLink,
     6→} from 'lucide-react';
     7→import type { CheckinLead, StaffMember } from '../types';
     8→import { api } from '../api/client';
     9→import { FilterDatePicker, PortalSelect } from '../components/ui';
    10→
    11→interface Props {
    12→  currentUser: StaffMember;
    13→  onRefreshLeads: () => Promise<void>;
    14→  onEditLead?: (lead: CheckinLead) => void;
    15→  allUsers?: StaffMember[];
    16→}
    17→
    18→const MONTHS = ['янв','фев','мар','апр','май','июн','июл','авг','сен','окт','ноя','дек'];
    19→const PAGE_SIZE = 30;
    20→
    21→function fmtDate(raw: string): string {
    22→  const d = new Date(raw);
    23→  return `${d.getUTCDate()} ${MONTHS[d.getUTCMonth()]}`;
    24→}
    25→
    26→function fmtDateShort(raw: string): string {
    27→  if (!raw) return '';
    28→  const d = new Date(raw);
    29→  return `${d.getUTCDate()} ${MONTHS[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
    30→}
    31→
    32→function fmtCreatedAt(raw: string): string {
    33→  if (!raw) return '';
    34→  const d = new Date(raw);
    35→  return `${d.getDate()} ${MONTHS[d.getMonth()]}`;
    36→}
    37→
    38→function fmtDateYcl(raw: string): string {
    39→  if (!raw) return '';
    40→  const parts = raw.split(' ');
    41→  const [year, month, day] = (parts[0] || '').split('-').map(Number);
    42→  const timePart = parts[1] || '';
    43→  const [hh, mm] = timePart.split(':').map(Number);
    44→  if (!year || !month || !day) return raw.slice(0, 10);
    45→  const time = timePart ? ` ${String(hh || 0).padStart(2, '0')}:${String(mm || 0).padStart(2, '0')}` : '';
    46→  return `${day} ${MONTHS[month - 1]}${time}`;
    47→}
    48→
    49→function mskDateStr(offsetDays: number): string {
    50→  const d = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Moscow' }));
    51→  d.setDate(d.getDate() + offsetDays);
    52→  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    53→}
    54→
    55→function daysAgo(raw: string): string {
    56→  const todayMsk = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Moscow' }));
    57→  todayMsk.setHours(0, 0, 0, 0);
    58→  const date = new Date(raw);
    59→  const bookDay = new Date(Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate()));
    60→  const diff = Math.floor((todayMsk.getTime() - bookDay.getTime()) / 86_400_000);
    61→  if (diff === 1) return 'вчера';
    62→  if (diff === 0) return 'сегодня';
    63→  if (diff <= 4) return `${diff} дня`;
    64→  return `${diff} дн`;
    65→}
    66→
    67→function fmtPhone(p: string): string {
    68→  if (!p) return '';
    69→  const d = p.replace(/\D/g, '');
    70→  if (d.length === 11) return `+7 (${d.slice(1,4)}) ${d.slice(4,7)}-${d.slice(7,9)}-${d.slice(9,11)}`;
    71→  return p;
    72→}
    73→
    74→function fmtMoney(n: number): string {
    75→  return n.toLocaleString('ru') + '\u00a0₽';
    76→}
    77→
    78→type YclientsFilter = 'all' | 'no_data' | 'waiting' | 'confirmed' | 'showed' | 'no_show_ycl' | 'deleted';
    79→type DepositFilter  = 'all' | 'paid' | 'not_paid' | 'no_deposit';
    80→
    81→const RECORD_STATUS: Record<string, { text: string; cls: string }> = {
    82→  booked:      { text: 'Запись',     cls: 'bg-indigo-50 text-indigo-600 border-indigo-200' },
    83→  rescheduled: { text: 'Перенос',    cls: 'bg-amber-50 text-amber-600 border-amber-200'   },
    84→  showed_up:   { text: 'Пришёл ✓',  cls: 'bg-emerald-50 text-emerald-700 border-emerald-200' },
    85→  no_show:     { text: 'Не пришёл', cls: 'bg-rose-50 text-rose-600 border-rose-200'       },
    86→  cancelled:   { text: 'Отменено',  cls: 'bg-neutral-100 text-neutral-500 border-neutral-200' },
    87→};
    88→
    89→function yclLabel(att: number | null, deleted?: boolean | null, hasOther?: boolean) {
    90→  if (deleted) return { text: 'Удалено',        cls: 'text-neutral-500', dot: 'bg-neutral-400' };
    91→  switch (att) {
    92→    case  1: return { text: 'Пришёл',           cls: 'text-emerald-700', dot: 'bg-emerald-500' };
    93→    case -1: return { text: 'Не пришёл',        cls: 'text-rose-700',    dot: 'bg-rose-500'    };
    94→    case  0: return { text: 'Ожидание',         cls: 'text-amber-700',   dot: 'bg-amber-400'   };
    95→    case  2: return { text: 'Подтвердил',       cls: 'text-indigo-700',  dot: 'bg-indigo-500'  };
    96→    default:
    97→      if (hasOther) return { text: 'Перенесена',      cls: 'text-amber-600',   dot: 'bg-amber-400'   };
    98→      return            { text: 'Запись не найдена', cls: 'text-neutral-400', dot: 'bg-neutral-300' };
    99→  }
   100→}
   101→
   102→function PillGroup<T extends string>({
   103→  value, onChange, options,
   104→}: {
   105→  value: T; onChange: (v: T) => void; options: { id: T; label: string }[];
   106→}) {
   107→  return (
   108→    <div className="flex gap-1 overflow-x-auto no-scrollbar">
   109→      {options.map(o => (
   110→        <button
   111→          key={o.id}
   112→          onClick={() => onChange(o.id)}
   113→          className={`shrink-0 px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wider transition-colors duration-150 cursor-pointer whitespace-nowrap select-none border ${
   114→            value === o.id
   115→              ? 'bg-neutral-950 text-white border-neutral-950'
   116→              : 'bg-white/60 text-neutral-500 border-neutral-200/70 hover:text-neutral-800 hover:bg-white'
   117→          }`}
   118→        >
   119→          {o.label}
   120→        </button>
   121→      ))}
   122→    </div>
   123→  );
   124→}
