   126→function CopyAmoId({ id }: { id: string }) {
   127→  const [copied, setCopied] = useState(false);
   128→  const copy = (e: React.MouseEvent) => {
   129→    e.stopPropagation();
   130→    navigator.clipboard.writeText(id).then(() => {
   131→      setCopied(true);
   132→      setTimeout(() => setCopied(false), 1500);
   133→    });
   134→  };
   135→  return (
   136→    <div className="flex items-center gap-1 group">
   137→      <a
   138→        href={`https://wuuuu.amocrm.ru/leads/detail/${id}`}
   139→        target="_blank"
   140→        rel="noopener noreferrer"
   141→        onClick={e => e.stopPropagation()}
   142→        className="flex items-center gap-1 text-[10px] text-neutral-400 hover:text-neutral-700 transition-colors font-medium"
   143→      >
   144→        <span className="text-[8px] font-bold uppercase tracking-wider bg-neutral-100 text-neutral-400 px-1.5 py-0.5 rounded leading-none">AmoCRM</span>
   145→        <span className="font-mono">{id}</span>
   146→        <ExternalLink className="w-3 h-3 shrink-0 opacity-0 group-hover:opacity-100 transition-opacity" />
   147→      </a>
   148→      <button onClick={copy} className="opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer ml-0.5" title="Скопировать ID">
   149→        {copied ? <Check className="w-3 h-3 text-emerald-500" /> : <Copy className="w-3 h-3 text-neutral-400" />}
   150→      </button>
   151→    </div>
   152→  );
   153→}
   154→
   155→function CopyPhoneCheckin({ phone }: { phone: string }) {
   156→  const [copied, setCopied] = useState(false);
   157→  const copy = (e: React.MouseEvent) => {
   158→    e.preventDefault();
   159→    e.stopPropagation();
   160→    navigator.clipboard.writeText(phone).then(() => { setCopied(true); setTimeout(() => setCopied(false), 1500); });
   161→  };
   162→  return (
   163→    <div className="flex items-center gap-1 group">
   164→      <a href={`tel:${phone}`} onClick={e => e.stopPropagation()} className="flex items-center gap-1 text-[10px] text-neutral-500 hover:text-neutral-800 transition-colors font-medium">
   165→        <Phone className="w-3 h-3 text-neutral-400 shrink-0" />
   166→        {fmtPhone(phone)}
   167→      </a>
   168→      <button onClick={copy} className="opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer ml-0.5" title="Скопировать номер">
   169→        {copied ? <Check className="w-3 h-3 text-emerald-500" /> : <Copy className="w-3 h-3 text-neutral-400" />}
   170→      </button>
   171→    </div>
   172→  );
   173→}
   174→
   175→export default function CheckinPage({ currentUser, onRefreshLeads, onEditLead, allUsers = [] }: Props) {
   176→  const [items, setItems]         = useState<CheckinLead[]>([]);
   177→  const [loading, setLoading]     = useState(true);
   178→  const [busy, setBusy]           = useState<Set<string>>(new Set());
   179→  const [dismissed, setDismissed] = useState<Set<string>>(new Set());
   180→  const [fading, setFading]       = useState<Set<string>>(new Set());
   181→
   182→  const [searchInput, setSearchInput]     = useState('');
   183→  const [search, setSearch]               = useState('');
   184→  const [managerFilter, setManagerFilter] = useState('all');
   185→  const [dateFrom, setDateFrom]           = useState('');
   186→  const [dateTo, setDateTo]               = useState('');
   187→  const [ycFilter, setYcFilter]           = useState<YclientsFilter>('all');
   188→  const [depFilter, setDepFilter]         = useState<DepositFilter>('all');
   189→  const [cityFilter, setCityFilter]       = useState('all');
   190→  const [showChecked, setShowChecked]     = useState(false);
   191→
   192→  const [selected, setSelected] = useState<Set<string>>(new Set());
   193→  const [bulkBusy, setBulkBusy] = useState(false);
   194→  const [page, setPage]         = useState(1);
   195→  const [showAll, setShowAll]   = useState(false);
   196→
   197→  const isAdmin = currentUser.role === 'admin';
   198→
   199→  useEffect(() => {
   200→    const t = setTimeout(() => setSearch(searchInput), 200);
   201→    return () => clearTimeout(t);
   202→  }, [searchInput]);
   203→
   204→  const fetchItems = useCallback(async () => {
   205→    setLoading(true);
   206→    try {
   207→      const data = await api.checkin.list(currentUser.name, currentUser.role);
   208→      setItems(data);
   209→      setDismissed(new Set());
   210→      setFading(new Set());
   211→    } catch { /* ignore */ }
   212→    setLoading(false);
   213→  }, [currentUser.name, currentUser.role]);
   214→
   215→  useEffect(() => { fetchItems(); }, [fetchItems]);
   216→
   217→  const handleStatus = async (id: string, status: 'showed_up' | 'no_show') => {
   218→    setBusy(p => new Set(p).add(id));
   219→    try {
   220→      await api.checkin.quickUpdate(id, { status });
   221→      setFading(p => new Set(p).add(id));
   222→      setTimeout(() => {
   223→        setDismissed(p => new Set(p).add(id));
   224→        setFading(p => { const s = new Set(p); s.delete(id); return s; });
   225→      }, 500);
   226→      setSelected(p => { const s = new Set(p); s.delete(id); return s; });
   227→      await onRefreshLeads();
   228→      await fetchItems();
   229→    } catch { /* ignore */ }
   230→    setBusy(p => { const s = new Set(p); s.delete(id); return s; });
   231→  };
   232→
   233→  const [deleteBusy, setDeleteBusy] = useState<Set<string>>(new Set());
   234→
   235→  const handleDelete = async (id: string) => {
   236→    if (!confirm('Удалить эту запись?')) return;
   237→    setDeleteBusy(p => new Set(p).add(id));
   238→    try {
   239→      await api.leads.delete(id);
   240→      setDismissed(p => new Set(p).add(id));
   241→      await onRefreshLeads();
   242→      await fetchItems();
   243→    } catch { /* ignore */ }
   244→    setDeleteBusy(p => { const s = new Set(p); s.delete(id); return s; });
   245→  };
   246→
   247→  const handleBulkStatus = async (status: 'showed_up' | 'no_show') => {
   248→    setBulkBusy(true);
   249→    const ids = Array.from(selected);
   250→    await Promise.all(ids.map(id => api.checkin.quickUpdate(id, { status }).catch(() => {})));
   251→    ids.forEach(id => setFading(p => new Set(p).add(id)));
   252→    setTimeout(() => {
   253→      ids.forEach(id => setDismissed(p => new Set(p).add(id)));
   254→      setFading(new Set());
   255→    }, 500);
   256→    setSelected(new Set());
   257→    await onRefreshLeads();
   258→    await fetchItems();
   259→    setBulkBusy(false);
   260→  };
   261→
   262→  const uniqueManagers = useMemo(() =>
   263→    Array.from(new Set(items.map(l => l.managerName).filter(Boolean))).sort(),
   264→    [items]
   265→  );
   266→
   267→  const uniqueCities = useMemo(() =>
   268→    Array.from(new Set(items.map(l => l.city).filter(Boolean))).sort() as string[],
   269→    [items]
   270→  );
   271→
   272→  const filtered = useMemo(() => {
   273→    const term = search.toLowerCase();
   274→    return items.filter(l => {
   275→      if (dismissed.has(l.id ?? '')) return false;
   276→      if (!showChecked && (l.status === 'showed_up' || l.status === 'no_show' || l.status === 'cancelled')) return false;
   277→      if (term && !(
   278→        l.clientName.toLowerCase().includes(term) ||
   279→        (l.clientPhone && l.clientPhone.includes(term)) ||
   280→        (l.amocrmLeadId && l.amocrmLeadId.toLowerCase().includes(term))
   281→      )) return false;
   282→      if (managerFilter !== 'all' && l.managerName !== managerFilter) return false;
   283→      if (cityFilter !== 'all' && l.city !== cityFilter) return false;
   284→      const bd = String(l.bookingDate).slice(0, 10);
   285→      if (dateFrom && bd < dateFrom) return false;
   286→      if (dateTo   && bd > dateTo)   return false;
   287→      if (ycFilter !== 'all') {
   288→        if (ycFilter === 'deleted'     && !l.yclientsDeleted)                                    return false;
   289→        if (ycFilter === 'no_data'     && (l.yclientsDeleted || l.yclientsAttendance !== null))  return false;
   290→        if (ycFilter === 'waiting'     && (l.yclientsDeleted || l.yclientsAttendance !== 0))     return false;
   291→        if (ycFilter === 'confirmed'   && (l.yclientsDeleted || l.yclientsAttendance !== 2))     return false;
   292→        if (ycFilter === 'showed'      && (l.yclientsDeleted || l.yclientsAttendance !== 1))     return false;
   293→        if (ycFilter === 'no_show_ycl' && (l.yclientsDeleted || l.yclientsAttendance !== -1))   return false;
   294→      }
   295→      if (depFilter === 'paid'       && !l.yookassaPaid)   return false;
   296→      if (depFilter === 'not_paid'   && !!l.yookassaPaid)  return false;
   297→      if (depFilter === 'no_deposit' && (!!l.yookassaPaid || l.depositRequired)) return false;
   298→      return true;
   299→    });
   300→  }, [items, dismissed, search, managerFilter, cityFilter, dateFrom, dateTo, ycFilter, depFilter, showChecked]);
   301→
   302→  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
   303→
   304→  useEffect(() => { setPage(1); setSelected(new Set()); }, [search, managerFilter, cityFilter, dateFrom, dateTo, ycFilter, depFilter, showChecked]);
   305→
   306→  const paginated = useMemo(() =>
   307→    showAll ? filtered : filtered.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE),
   308→    [filtered, page, showAll]
   309→  );
   310→
   311→  const hasFilters = !!(search || searchInput || managerFilter !== 'all' || cityFilter !== 'all' || dateFrom || dateTo || ycFilter !== 'all' || depFilter !== 'all');
   312→
   313→  const resetFilters = () => {
   314→    setSearchInput(''); setSearch('');
   315→    setManagerFilter('all');
   316→    setCityFilter('all');
   317→    setDateFrom(''); setDateTo('');
   318→    setYcFilter('all');
   319→    setDepFilter('all');
   320→  };
   321→
   322→  const pendingOnPage = paginated.filter(l =>
   323→    (l.status === 'booked' || l.status === 'rescheduled') && !dismissed.has(l.id ?? '')
   324→  );
   325→
   326→  const allPageSelected = pendingOnPage.length > 0 && pendingOnPage.every(l => selected.has(l.id ?? ''));
   327→
   328→  const toggleSelectAll = () => {
   329→    if (allPageSelected) {
   330→      setSelected(p => {
   331→        const s = new Set(p);
   332→        pendingOnPage.forEach(l => s.delete(l.id ?? ''));
   333→        return s;
   334→      });
   335→    } else {
   336→      setSelected(p => {
   337→        const s = new Set(p);
   338→        pendingOnPage.forEach(l => s.add(l.id ?? ''));
   339→        return s;
   340→      });
   341→    }
   342→  };
   343→
   344→  if (loading) {
   345→    return (
   346→      <div className="flex items-center justify-center py-24">
   347→        <div className="w-6 h-6 border-2 border-indigo-600/30 border-t-indigo-600 rounded-full animate-spin" />
   348→      </div>
   349→    );
   350→  }
   351→
   352→  return (
   353→    <div className="space-y-4">
   354→
   355→      {/* Header */}
   356→      <div className="flex items-center justify-between gap-4">
   357→        <div>
   358→          <h2 className="text-sm font-display font-bold text-neutral-950 uppercase tracking-widest">
   359→            Проверка визитов
   360→          </h2>
   361→          <p className="text-[10px] text-neutral-400 font-bold uppercase tracking-widest mt-1">
   362→            {filtered.length === 0
   363→              ? 'Записей нет'
   364→              : `${filtered.length} ${filtered.length === 1 ? 'запись' : filtered.length < 5 ? 'записи' : 'записей'}`}
   365→            {totalPages > 1 && ` · стр. ${page}/${totalPages}`}
   366→          </p>
   367→        </div>
   368→        <div className="flex items-center gap-2">
   369→          {isAdmin && (
   370→            <button
   371→              onClick={() => setShowChecked(v => !v)}
   372→              className={`flex items-center gap-1.5 px-3 py-2 rounded-xl border text-[10px] font-bold uppercase tracking-wider transition-colors duration-150 cursor-pointer ${
   373→                showChecked
   374→                  ? 'bg-neutral-950 text-white border-neutral-950'
   375→                  : 'bg-white/60 text-neutral-500 border-neutral-200/70 hover:bg-white hover:text-neutral-800'
   376→              }`}
   377→            >
   378→              {showChecked ? <Eye className="w-3 h-3" /> : <EyeOff className="w-3 h-3" />}
   379→              {showChecked ? 'Все статусы' : 'Только ожидающие'}
   380→            </button>
   381→          )}
   382→          <button
   383→            onClick={fetchItems}
   384→            className="p-2.5 rounded-xl bg-white/50 border border-neutral-200/60 hover:bg-white transition-colors duration-150 shadow-sm cursor-pointer"
   385→          >
   386→            <RefreshCw className="w-3.5 h-3.5 text-neutral-400" />
   387→          </button>
   388→        </div>
   389→      </div>
   390→
   391→      {/* Filters */}
   392→      <div className="spatial-glass rounded-2xl p-4 flex flex-col gap-3">
   393→        <div className="relative">
   394→          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-neutral-400" />
   395→          <input
   396→            type="text"
   397→            placeholder="Клиент, телефон, номер AmoCRM..."
   398→            value={searchInput}
   399→            onChange={e => setSearchInput(e.target.value)}
   400→            className="w-full pl-10 pr-4 py-2.5 text-xs bg-white/50 focus:bg-white/90 border border-neutral-200/60 text-neutral-850 placeholder-neutral-400 rounded-xl focus:outline-hidden focus:border-neutral-400 transition-all duration-200 font-semibold shadow-3xs"
   401→          />
   402→          {searchInput && (
   403→            <button onClick={() => { setSearchInput(''); setSearch(''); }} className="absolute right-3.5 top-1/2 -translate-y-1/2 cursor-pointer">
   404→              <X className="w-3.5 h-3.5 text-neutral-400 hover:text-neutral-700" />
   405→            </button>
   406→          )}
   407→        </div>
   408→
   409→        <div className="flex flex-wrap items-center gap-2">
   410→          {[
   411→            { label: 'Вчера',  from: mskDateStr(-1), to: mskDateStr(-1) },
   412→            { label: 'Неделя', from: mskDateStr(-7), to: mskDateStr(0)  },
   413→            { label: 'Месяц',  from: mskDateStr(-30),to: mskDateStr(0)  },
   414→          ].map(p => {
   415→            const active = dateFrom === p.from && dateTo === p.to;
   416→            return (
   417→              <button
   418→                key={p.label}
   419→                onClick={() => active ? (setDateFrom(''), setDateTo('')) : (setDateFrom(p.from), setDateTo(p.to))}
   420→                className={`text-[10px] font-bold px-3 py-2 border rounded-xl transition-colors duration-150 cursor-pointer shrink-0 ${
   421→                  active ? 'bg-neutral-950 text-white border-neutral-950' : 'bg-white/60 text-neutral-500 border-neutral-200/70 hover:bg-white hover:text-neutral-800'
   422→                }`}
   423→              >{p.label}</button>
   424→            );
   425→          })}
   426→          <FilterDatePicker
   427→            label="Период"
   428→            valueFrom={dateFrom}
   429→            valueTo={dateTo}
   430→            onChange={(f, t) => { setDateFrom(f); setDateTo(t); }}
   431→          />
   432→          {isAdmin && (
   433→            <PortalSelect
   434→              value={managerFilter}
   435→              onChange={setManagerFilter}
   436→              options={uniqueManagers.map(m => ({ value: m, label: m }))}
   437→              allLabel="Все менеджеры"
   438→              allValue="all"
   439→            />
   440→          )}
   441→          {uniqueCities.length > 0 && (
